@namespace sv_da0154cc49074795860244a9c5835b83.Components.Pages.Apply

<h4 class="mb-3">Personal Information</h4>

<div class="mb-3">
    <label for="fullName" class="form-label">Full Name <span class="text-danger">*</span></label>
    <input id="fullName" type="text" class="form-control @(Errors.ContainsKey("FullName") ? "is-invalid" : "")"
           @bind="FullName" @bind:event="oninput" />
    @if (Errors.TryGetValue("FullName", out var nameError))
    {
        <div class="invalid-feedback">@nameError</div>
    }
</div>

<div class="mb-3">
    <label for="email" class="form-label">Email <span class="text-danger">*</span></label>
    <input id="email" type="email" class="form-control @(Errors.ContainsKey("Email") ? "is-invalid" : "")"
           @bind="Email" @bind:event="oninput" />
    @if (Errors.TryGetValue("Email", out var emailError))
    {
        <div class="invalid-feedback">@emailError</div>
    }
</div>

<div class="mb-3">
    <label for="phone" class="form-label">Phone <span class="text-danger">*</span></label>
    <input id="phone" type="tel" class="form-control @(Errors.ContainsKey("Phone") ? "is-invalid" : "")"
           @bind="Phone" @bind:event="oninput" />
    @if (Errors.TryGetValue("Phone", out var phoneError))
    {
        <div class="invalid-feedback">@phoneError</div>
    }
</div>

<div class="mb-3">
    <label for="address" class="form-label">Address <span class="text-danger">*</span></label>
    <textarea id="address" class="form-control @(Errors.ContainsKey("Address") ? "is-invalid" : "")"
              rows="2" @bind="Address" @bind:event="oninput"></textarea>
    @if (Errors.TryGetValue("Address", out var addrError))
    {
        <div class="invalid-feedback">@addrError</div>
    }
</div>

<div class="d-flex justify-content-end">
    <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next →</span>
        }
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public EventCallback<string> FullNameChanged { get; set; }
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public EventCallback<string> EmailChanged { get; set; }
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public EventCallback<string> PhoneChanged { get; set; }
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<string> AddressChanged { get; set; }

    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private Dictionary<string, string> Errors { get; set; } = new();
    private bool IsValidating { get; set; }

    private async Task HandleNext()
    {
        Errors.Clear();

        if (string.IsNullOrWhiteSpace(FullName))
            Errors["FullName"] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(Email))
            Errors["Email"] = "Email is required.";
        if (string.IsNullOrWhiteSpace(Phone))
            Errors["Phone"] = "Phone is required.";
        if (string.IsNullOrWhiteSpace(Address))
            Errors["Address"] = "Address is required.";

        if (Errors.Count > 0) return;

        IsValidating = true;
        try
        {
            var emailValid = await ValidateEmail(Email);
            if (!emailValid)
            {
                Errors["Email"] = "Please enter a valid email address.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            IsValidating = false;
        }
    }
}

@namespace sv_da0154cc49074795860244a9c5835b83.Components.Pages.Apply

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-start mb-2">
            <h6 class="card-title mb-0">Position @(Index + 1)</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Company" @oninput="e => CompanyChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Title" @oninput="e => TitleChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" value="@StartDate?.ToString("yyyy-MM-dd")"
                       @onchange="e => StartDateChanged.InvokeAsync(DateTime.TryParse(e.Value?.ToString(), out var d) ? d : null)" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@EndDate?.ToString("yyyy-MM-dd")"
                       disabled="@IsCurrent"
                       @onchange="e => EndDateChanged.InvokeAsync(DateTime.TryParse(e.Value?.ToString(), out var d) ? d : null)" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"current-{Index}")"
                           checked="@IsCurrent"
                           @onchange="e => IsCurrentChanged.InvokeAsync((bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"current-{Index}")">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="2" value="@Description"
                          @oninput="e => DescriptionChanged.InvokeAsync(e.Value?.ToString() ?? "")"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }

    [Parameter] public string Company { get; set; } = "";
    [Parameter] public EventCallback<string> CompanyChanged { get; set; }
    [Parameter] public string Title { get; set; } = "";
    [Parameter] public EventCallback<string> TitleChanged { get; set; }
    [Parameter] public DateTime? StartDate { get; set; }
    [Parameter] public EventCallback<DateTime?> StartDateChanged { get; set; }
    [Parameter] public DateTime? EndDate { get; set; }
    [Parameter] public EventCallback<DateTime?> EndDateChanged { get; set; }
    [Parameter] public bool IsCurrent { get; set; }
    [Parameter] public EventCallback<bool> IsCurrentChanged { get; set; }
    [Parameter] public string Description { get; set; } = "";
    [Parameter] public EventCallback<string> DescriptionChanged { get; set; }

    [Parameter] public EventCallback OnRemove { get; set; }
}

