@namespace sv_da0154cc49074795860244a9c5835b83.Components.Pages.Apply

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];
    <WorkEntryEditor Index="index"
                     CanRemove="Entries.Count > 1"
                     Company="@entry.Company"
                     CompanyChanged="v => UpdateEntry(index, entry with { Company = v })"
                     Title="@entry.Title"
                     TitleChanged="v => UpdateEntry(index, entry with { Title = v })"
                     StartDate="@entry.StartDate"
                     StartDateChanged="v => UpdateEntry(index, entry with { StartDate = v })"
                     EndDate="@entry.EndDate"
                     EndDateChanged="v => UpdateEntry(index, entry with { EndDate = v })"
                     IsCurrent="@entry.IsCurrent"
                     IsCurrentChanged="v => UpdateEntry(index, entry with { IsCurrent = v, EndDate = v ? null : entry.EndDate })"
                     Description="@entry.Description"
                     DescriptionChanged="v => UpdateEntry(index, entry with { Description = v })"
                     OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<WorkEntryModel>> EntriesChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage { get; set; }

    private async Task UpdateEntry(int index, WorkEntryModel updated)
    {
        Entries[index] = updated;
        await EntriesChanged.InvokeAsync(Entries);
    }

    private async Task AddEntry()
    {
        Entries.Add(new WorkEntryModel());
        await EntriesChanged.InvokeAsync(Entries);
    }

    private async Task RemoveEntry(int index)
    {
        Entries.RemoveAt(index);
        await EntriesChanged.InvokeAsync(Entries);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;
        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) || entry.StartDate == null)
            {
                ErrorMessage = "Please fill in company, title, and start date for all positions.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }

    public record WorkEntryModel
    {
        public string Company { get; init; } = "";
        public string Title { get; init; } = "";
        public DateTime? StartDate { get; init; }
        public DateTime? EndDate { get; init; }
        public bool IsCurrent { get; init; }
        public string Description { get; init; } = "";
    }
}

@namespace sv_da0154cc49074795860244a9c5835b83.Components.Pages.Apply

<h4 class="mb-3">References</h4>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var r = References[index];
    <ReferenceEditor Index="index"
                     CanRemove="References.Count > 2"
                     Name="@r.Name"
                     NameChanged="v => UpdateRef(index, r with { Name = v })"
                     Relationship="@r.Relationship"
                     RelationshipChanged="v => UpdateRef(index, r with { Relationship = v })"
                     Email="@r.Email"
                     EmailChanged="v => UpdateRef(index, r with { Email = v })"
                     Phone="@r.Phone"
                     PhoneChanged="v => UpdateRef(index, r with { Phone = v })"
                     OnRemove="() => RemoveRef(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddRef">
        + Add Reference
    </button>
}

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<ReferenceModel>> ReferencesChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage { get; set; }

    private async Task UpdateRef(int index, ReferenceModel updated)
    {
        References[index] = updated;
        await ReferencesChanged.InvokeAsync(References);
    }

    private async Task AddRef()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
            await ReferencesChanged.InvokeAsync(References);
        }
    }

    private async Task RemoveRef(int index)
    {
        References.RemoveAt(index);
        await ReferencesChanged.InvokeAsync(References);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;
        if (References.Count < 2)
        {
            ErrorMessage = "Please provide at least 2 references.";
            return;
        }
        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                ErrorMessage = "Please fill in all fields for each reference.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }

    public record ReferenceModel
    {
        public string Name { get; init; } = "";
        public string Relationship { get; init; } = "";
        public string Email { get; init; } = "";
        public string Phone { get; init; } = "";
    }
}

@namespace sv_da0154cc49074795860244a9c5835b83.Components.Pages.Apply

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <label for="coverLetter" class="form-label">Write your cover letter</label>
    <textarea id="coverLetter" class="form-control" rows="10" maxlength="@MaxLength"
              value="@CoverLetter"
              @oninput="HandleInput"></textarea>
    <div class="form-text text-end">
        @(CoverLetter?.Length ?? 0) / @MaxLength characters
    </div>
</div>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        if (value.Length > MaxLength)
            value = value[..MaxLength];
        CoverLetter = value;
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;
        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            ErrorMessage = "Please write a cover letter.";
            return;
        }
        await OnNext.InvokeAsync();
    }
}

@namespace sv_da0154cc49074795860244a9c5835b83.Components.Pages.Apply

@using static WorkHistoryStep
@using static ReferencesStep

<h4 class="mb-3">Review Your Application</h4>

@if (IsSubmitted)
{
    <div class="alert alert-success text-center py-4">
        <h5 class="mb-2">🎉 Application Submitted!</h5>
        <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong>. We'll be in touch!</p>
    </div>
}
else
{
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@FullName</dd>
                <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Email</dd>
                <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Phone</dd>
                <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Address</dd>
            </dl>
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-no-border">
                    <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
                    <small class="text-muted">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </small>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mt-1 mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> — @r.Relationship<br />
                    <small class="text-muted">@r.Email · @r.Phone</small>
                </div>
            }
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(4)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    <div class="d-flex justify-content-between">
        <button type="button" class="btn btn-secondary" @onclick="OnBack">← Back</button>
        <button type="button" class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Application</span>
            }
        </button>
    </div>
}

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public string CoverLetter { get; set; } = "";

    [Parameter, EditorRequired] public EventCallback<int> OnEditStep { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public Func<Task<int>> SubmitApplication { get; set; } = default!;

    private bool IsSubmitting { get; set; }
    private bool IsSubmitted { get; set; }
    private int ApplicationId { get; set; }
    private string? ErrorMessage { get; set; }

    private async Task HandleSubmit()
    {
        IsSubmitting = true;
        ErrorMessage = null;
        try
        {
            ApplicationId = await SubmitApplication();
            IsSubmitted = true;
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

