@page "/apply"
@rendermode InteractiveServer

@using sv_da0154cc49074795860244a9c5835b83.Components.Pages.Apply
@using sv_da0154cc49074795860244a9c5835b83.Models
@using sv_da0154cc49074795860244a9c5835b83.Services
@using static WorkHistoryStep
@using static ReferencesStep

@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" CompletedSteps="completedSteps" OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 1:
            <PersonalInfoStep @bind-FullName="fullName"
                              @bind-Email="email"
                              @bind-Phone="phone"
                              @bind-Address="address"
                              ValidateEmail="ApplicationService.ValidateEmailAsync"
                              OnNext="() => AdvanceToStep(2)" />
            break;

        case 2:
            <WorkHistoryStep @bind-Entries="workEntries"
                             OnNext="() => AdvanceToStep(3)"
                             OnBack="() => GoToStep(1)" />
            break;

        case 3:
            <ReferencesStep @bind-References="references"
                            OnNext="() => AdvanceToStep(4)"
                            OnBack="() => GoToStep(2)" />
            break;

        case 4:
            <CoverLetterStep @bind-CoverLetter="coverLetter"
                             OnNext="() => AdvanceToStep(5)"
                             OnBack="() => GoToStep(3)" />
            break;

        case 5:
            <ReviewStep FullName="fullName"
                        Email="email"
                        Phone="phone"
                        Address="address"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="coverLetter"
                        OnEditStep="GoToStep"
                        OnBack="() => GoToStep(4)"
                        SubmitApplication="SubmitAsync" />
            break;
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();

    // Step 1
    private string fullName = "";
    private string email = "";
    private string phone = "";
    private string address = "";

    // Step 2
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };

    // Step 3
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4
    private string coverLetter = "";

    private void AdvanceToStep(int step)
    {
        completedSteps.Add(currentStep);
        currentStep = step;
    }

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private async Task<int> SubmitAsync()
    {
        var workHistory = new WorkHistory(
            workEntries.Select(e => new WorkEntry(
                e.Company, e.Title, e.StartDate ?? DateTime.MinValue, e.IsCurrent ? null : e.EndDate, e.Description
            )).ToList()
        );

        var refs = references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
        var personalInfo = new PersonalInfo(fullName, email, phone, address);
        var application = new JobApplication(personalInfo, workHistory, refs, coverLetter);

        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

